#include <bits/stdc++.h>
using namespace std;

// Simple recursive flatten for JSON using nlohmann::json (single header).
#include <nlohmann/json.hpp>
using json = nlohmann::json;

void flatten(const json &j, const string &prefix, vector<pair<string,string>> &out){
    for (auto &el : j.items()) {
        string new_key = prefix + (prefix.empty() ? "" : ".") + el.key();
        if (el.value().is_object()) {
            flatten(el.value(), new_key, out);
        } else {
            out.push_back({new_key, el.value().dump()});
        }
    }
}

