import json

def flatten(json_obj, prefix, out):
    for key, value in json_obj.items():
        new_key = prefix + ("" if prefix == "" else ".") + key
        if isinstance(value, dict):
            flatten(value, new_key, out)
        else:
            out.append((new_key, str(value)))

